1	export interface QuoteInput {
2	  items: { type: string; cursed?: boolean; enchantment?: number }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BLOCK_SIZE = 3;
8	const BLOCK_PRICE = 60;
9	
10	const CURSE_SURCHARGE_RATE = 0.5;
11	
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	export function quote(input: QuoteInput): number {
25	  const countsByType: Record<string, number> = {};
26	  for (const item of input.items) {
27	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
28	  }
29	
30	  let basePremiumTotal = 0;
31	  for (const type of Object.keys(countsByType)) {
32	    const count = countsByType[type];
33	    if (count === BLOCK_SIZE) {
34	      basePremiumTotal += BLOCK_PRICE;
35	    } else {
36	      basePremiumTotal += count * BASE_PREMIUMS[type];
37	    }
38	  }
39	
40	  let surchargeTotal = 0;
41	  for (const item of input.items) {
42	    if (item.cursed) {
43	      surchargeTotal += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
44	    }
45	    if (
46	      item.enchantment !== undefined &&
47	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
48	    ) {
49	      surchargeTotal +=
50	        BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
51	    }
52	  }
53	
54	  return basePremiumTotal + surchargeTotal + PROCESSING_FEE;
55	}
56	
57	export function claim(): number {
58	  return undefined as unknown as number;
59	}
